function random(min, max, decimals = 1) {
    return Number(
        (Math.random() * (max - min) + min).toFixed(decimals)
    );
}

function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function pickRandom(items) {
    return items[randomInt(0, items.length - 1)];
}

/*
 * Liste des capteurs et de leurs sites.
 */
const sensors = [
    {
        deviceId: "ESP01",
        siteId: "SITE-SP-001",
        site: "San-Pedro Nord",
        lotId: "LOT-2026-001"
    },
    {
        deviceId: "ESP02",
        siteId: "SITE-SB-001",
        site: "Soubré",
        lotId: "LOT-2026-002"
    },
    {
        deviceId: "ESP03",
        siteId: "SITE-GB-001",
        site: "Grand-Béréby",
        lotId: "LOT-2026-003"
    },
    {
        deviceId: "ESP04",
        siteId: "SITE-DL-001",
        site: "Daloa",
        lotId: "LOT-2026-004"
    }
];

/*
 * Scénarios possibles.
 *
 * Pondération :
 * - 60 % normal
 * - 25 % fraude
 * - 15 % maintenance
 */
const scenarioRoll = Math.random();

let scenarioType;

if (scenarioRoll < 0.60) {
    scenarioType = "NORMAL";
} else if (scenarioRoll < 0.85) {
    scenarioType = "FRAUDE";
} else {
    scenarioType = "MAINTENANCE";
}

const selectedSensor = pickRandom(sensors);

let values;
let anomalyType = null;

/*
 * Mesures normales et vraisemblables.
 */
if (scenarioType === "NORMAL") {
    values = {
        temperature: random(34, 40),
        humidity: random(52, 70),
        co2: randomInt(480, 850),
        light: randomInt(50000, 75000),
        battery: randomInt(60, 100),
        signal: randomInt(-78, -58)
    };
}

/*
 * Mesures frauduleuses.
 * Une anomalie est choisie au hasard.
 */
if (scenarioType === "FRAUDE") {
    const fraudType = randomInt(1, 4);

    if (fraudType === 1) {
        anomalyType = "TEMPERATURE_ELEVEE";

        values = {
            temperature: random(55, 85),
            humidity: random(52, 70),
            co2: randomInt(480, 850),
            light: randomInt(50000, 75000),
            battery: randomInt(60, 100),
            signal: randomInt(-78, -58)
        };
    }

    if (fraudType === 2) {
        anomalyType = "HUMIDITE_TROP_BASSE";

        values = {
            temperature: random(34, 40),
            humidity: random(3, 18),
            co2: randomInt(480, 850),
            light: randomInt(50000, 75000),
            battery: randomInt(60, 100),
            signal: randomInt(-78, -58)
        };
    }

    if (fraudType === 3) {
        anomalyType = "CO2_TROP_ELEVE";

        values = {
            temperature: random(34, 40),
            humidity: random(52, 70),
            co2: randomInt(1600, 3000),
            light: randomInt(50000, 75000),
            battery: randomInt(60, 100),
            signal: randomInt(-78, -58)
        };
    }

    if (fraudType === 4) {
        anomalyType = "ANOMALIES_MULTIPLES";

        values = {
            temperature: random(55, 85),
            humidity: random(3, 18),
            co2: randomInt(1600, 3000),
            light: randomInt(1000, 15000),
            battery: randomInt(40, 90),
            signal: randomInt(-82, -60)
        };
    }
}

/*
 * Situation de maintenance :
 * valeurs environnementales normales,
 * mais batterie ou signal dégradé.
 */
if (scenarioType === "MAINTENANCE") {
    const maintenanceType = randomInt(1, 3);

    if (maintenanceType === 1) {
        anomalyType = "BATTERIE_FAIBLE";

        values = {
            temperature: random(34, 40),
            humidity: random(52, 70),
            co2: randomInt(480, 850),
            light: randomInt(50000, 75000),
            battery: randomInt(1, 14),
            signal: randomInt(-78, -58)
        };
    }

    if (maintenanceType === 2) {
        anomalyType = "SIGNAL_FAIBLE";

        values = {
            temperature: random(34, 40),
            humidity: random(52, 70),
            co2: randomInt(480, 850),
            light: randomInt(50000, 75000),
            battery: randomInt(60, 100),
            signal: randomInt(-98, -86)
        };
    }

    if (maintenanceType === 3) {
        anomalyType = "BATTERIE_ET_SIGNAL_FAIBLES";

        values = {
            temperature: random(34, 40),
            humidity: random(52, 70),
            co2: randomInt(480, 850),
            light: randomInt(50000, 75000),
            battery: randomInt(1, 14),
            signal: randomInt(-98, -86)
        };
    }
}

/*
 * Message final envoyé sur MQTT.
 */
const data = {
    ...selectedSensor,
    ...values,

    simulationType: scenarioType,
    anomalyType: anomalyType,

    timestamp: new Date().toISOString()
};

msg.payload = JSON.stringify(data);

return msg;

const d = msg.payload;

let alerts = [];
let fraudScore = 0;

if (!d.deviceId || !d.timestamp) {
    alerts.push("Message incomplet");
    fraudScore += 40;
}

if (d.temperature < 20 || d.temperature > 50) {
    alerts.push("Température incohérente");
    fraudScore += 30;
}

if (d.humidity < 20 || d.humidity > 85) {
    alerts.push("Humidité incohérente");
    fraudScore += 30;
}

if (d.co2 < 300 || d.co2 > 1500) {
    alerts.push("CO2 incohérent");
    fraudScore += 20;
}

if (d.battery < 10) {
    alerts.push("Batterie très faible");
    fraudScore += 10;
}

d.fraudScore = fraudScore;
d.isFraud = fraudScore >= 30;
d.alerts = alerts;

/*
Sortie 1 :
Toutes les mesures, normales ou frauduleuses,
continuent vers InfluxDB.
*/
const msgMesure = {
    ...msg,
    topic: d.isFraud ? "mesure_frauduleuse" : "mesure_normale",
    payload: d
};

/*
Sortie 2 :
Uniquement les alertes frauduleuses
partent vers MongoDB.
*/
let msgAlerte = null;

if (d.isFraud) {
    msgAlerte = {
        topic: "fraude",
        payload: {
            type: "FRAUDE",
            niveau: "CRITICAL",
            deviceId: d.deviceId,
            siteId: d.siteId,
            site: d.site,
            lotId: d.lotId,
            fraudScore: d.fraudScore,
            alerts: d.alerts,
            mesure: d,
            createdAt: new Date().toISOString()
        }
    };
}

return [msgMesure, msgAlerte];

const d = msg.payload;

msg.payload = [
    {
        temperature: d.temperature,
        humidity: d.humidity,
        co2: d.co2,
        light: d.light,
        battery: d.battery,
        signal: d.signal,
        fraudScore: d.fraudScore || 0
    },
    {
        deviceId: d.deviceId,
        site: d.site,
        lotId: d.lotId
    }
];

return msg;
